#include <stdio.h>
#include <stdlib.h>
#include <math.h>

typedef struct Point {
 double x, y;
} Point;

typedef struct Cluster {
 Point centroid;
 int size;
} Cluster;

Cluster* hierarchical_clustering(Point* points, int n, int K) {
 Cluster* clusters = (Cluster*) malloc(K * sizeof(Cluster));
 for (int i = 0; i < K; i++) {
 clusters[i].centroid.x = points[i].x;
 clusters[i].centroid.y = points[i].y;
 clusters[i].size = 1;
 }
 for (int i = K; i < n; i++) {
 double min_distance = INFINITY;
 int nearest_cluster = -1;
 for (int j = 0; j < K; j++) {
 double distance = sqrt(pow(points[i].x - clusters[j].centroid.x, 2) + pow(points[i].y - clusters[j].centroid.y, 2));
 if (distance < min_distance) {
 min_distance = distance;
 nearest_cluster = j;
 }
 }
 clusters[nearest_cluster].centroid.x = (clusters[nearest_cluster].centroid.x * clusters[nearest_cluster].size + points[i].x) / (clusters[nearest_cluster].size + 1);
 clusters[nearest_cluster].centroid.y = (clusters[nearest_cluster].centroid.y * clusters[nearest_cluster].size + points[i].y) / (clusters[nearest_cluster].size + 1);
 clusters[nearest_cluster].size++;
 }
 return clusters;
}

int main() {
 int n = 100;
 int K = 3;
 Point points[n];
 for (int i = 0; i < n; i++) {
 points[i].x = (double) rand() / RAND_MAX;
 points[i].y = (double) rand() / RAND_MAX;
 }
 Cluster* clusters = hierarchical_clustering(points, n, K);
 for (int i = 0; i < K; i++) {
 printf("Cluster %d: (%f, %f) - %d points\n", i, clusters[i].centroid.x, clusters[i].centroid.y, clusters[i].size);
 }
 free(clusters);
 return 0;
}
